// \u7B2C\u4E00\u79CD\u60C5\u51B5\uFF1A
// fn \u63D0\u5347\u5230 {} \u5916\u8FB9\uFF0Cfn \u63D0\u5347\u81EA\u6B64\u5904
{
  function fn() {
    console.log('fn')
  }
}

fn()

// \u51FD\u6570\u4F5C\u7528\u57DF
// \u7B2C\u4E8C\u79CD\u60C5\u51B5\uFF1A
!(function () {
  // fn \u63D0\u5347\u81EA\u6B64\u5904
  fn()
  function fn() {
    console.log('fn')
  }
})()

// \u51FD\u6570\u4F5C\u7528\u57DF\u5D4C\u5957\u5757\u7EA7\u4F5C\u7528\u57DF
// \u7B2C\u4E09\u79CD\u60C5\u51B5\uFF1A
;(function () {
  // fn() fn is not a function
  if (1) {
    // fn \u63D0\u5347\u81EA\u6B64\u5904
    fn()
    function fn() {
      console.log('fn')
    }
  }
})()
`,paraId:7,tocIndex:3},{value:"\u8003\u8651\u5230\u73AF\u5883\u5BFC\u81F4\u7684\u884C\u4E3A\u5DEE\u5F02\u592A\u5927\uFF0C\u5E94\u8BE5\u907F\u514D\u5728\u5757\u7EA7\u4F5C\u7528\u57DF\u5185\u58F0\u660E\u51FD\u6570",paraId:8,tocIndex:3},{value:"\u3002",paraId:8,tocIndex:3},{value:`// TDZ \u53EF\u4EE5\u7B80\u5355\u7406\u89E3\u4E3A let \u4E5F\u5B58\u5728\u53D8\u91CF\u63D0\u5347\uFF08\u4E0D\u5B8C\u5168\u6B63\u786E\u4F46\u4FBF\u4E8E\u8BB0\u5FC6\uFF09
