// ?: \u5339\u914D\u4E0D\u6355\u83B7

console.log(
  /^(\\d{6})(\\d{4})(\\d{2})(\\d{2})\\d{2}(\\d)(?:\\d|X)$/.exec('320101198904196476'),
)

