// \u7528\u5B57\u7B26\u4E32\u7684\u5F0A\u7AEF\u7C7B\u4F3C\u6B63\u5219\u7684\u61D2\u60F0\u6027\uFF0C\u6B63\u5219\u4E0D\u52A0 g \u6548\u679C\u7C7B\u4F3C

